-- CEQA
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_169', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Pub. Res. Code §§ 21000-21189.3 (California Environmental Quality Act)', 'PRC §§ 21000-21189.3 / CEQA', 'California Environmental Quality Act — Environmental Review of Projects', 'CEQA requires state and local agencies to evaluate the environmental effects of discretionary projects before approval. If a project may cause significant environmental effects, an Environmental Impact Report (EIR) must be prepared. Negative Declaration if no significant impact. Mitigated Negative Declaration if impacts can be mitigated. Categorical and statutory exemptions exist. 30-day statute of limitations for CEQA challenges (35 days for EIR). CEQA Guidelines in 14 CCR §§ 15000-15387.', '["Applies to discretionary projects by public agencies","Lead agency determines if project may have significant environmental effect","Three tiers: Exempt → Negative Declaration → EIR","EIR must analyze significant environmental effects and alternatives","Mitigation measures required for significant impacts","Public notice and comment period required","Cumulative impacts must be analyzed","Must consider reasonable range of alternatives including no project","Findings of fact and statement of overriding considerations for significant unavoidable impacts","30-day statute of limitations for CEQA challenges (35 days for EIR)","CEQA Guidelines: 14 CCR §§ 15000-15387"]', '[{"section":"21060.5","description":"Definition of environment"},{"section":"21065","description":"Definition of project — discretionary approval"},{"section":"21080","description":"Applicability — discretionary projects"},{"section":"21080.1","description":"Lead agency determination"},{"section":"21100","description":"EIR requirements — contents"},{"section":"21064","description":"Negative Declaration — no significant effect"},{"section":"21064.5","description":"Mitigated Negative Declaration"},{"section":"21080.5-21084","description":"Exemptions — categorical and statutory"},{"section":"21167","description":"Statute of limitations — 30/35 days"},{"section":"21168.6-21189.3","description":"Streamlining provisions — SB 375, infill, transit priority"}]', '["EIR","negative_declaration","mitigated_negative_declaration","initial_study","notice_of_preparation","notice_of_determination","CEQA_exemption","mitigation_monitoring_plan","statement_of_overriding_considerations","CEQA_petition"]', '["california-regulatory-compliance-audit"]', 'Lead Agency / Superior Court (judicial review)', 1, 1, datetime('now'), datetime('now'));

-- NEPA
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_170', 'REGULIS', 'FEDERAL_STATUTE', 'US', '42 USC §§ 4321-4370h (National Environmental Policy Act)', '42 USC §§ 4321-4370h / NEPA', 'National Environmental Policy Act — Federal Environmental Review', 'NEPA requires federal agencies to assess environmental effects of proposed major federal actions significantly affecting the quality of the human environment. Three levels of review: Categorical Exclusion (no significant effect), Environmental Assessment (EA) with Finding of No Significant Impact (FONSI), or full Environmental Impact Statement (EIS). Council on Environmental Quality (CEQ) issues regulations (40 CFR Parts 1500-1508). No private right of action under NEPA itself — enforcement via APA § 706.', '["Applies to major federal actions significantly affecting human environment","Federal agencies must prepare detailed statement of environmental impact","Three tiers: Categorical Exclusion → EA/FONSI → EIS","EIS must analyze: environmental impact, unavoidable adverse effects, alternatives, irreversible commitments","Scoping process: public participation in identifying issues","Draft EIS → public comment → Final EIS → Record of Decision (ROD)","Must consider reasonable alternatives including no action","Cumulative impacts analysis required","CEQ regulations: 40 CFR Parts 1500-1508","No private right of action — judicial review under APA § 706","Arbitrary and capricious standard of review"]', '[{"section":"4321","description":"Congressional declaration of purpose"},{"section":"4332(C)","description":"Detailed statement requirement — EIS for major federal actions"},{"section":"4332(E)","description":"Study and develop alternatives"},{"section":"4342","description":"Council on Environmental Quality established"},{"section":"40 CFR 1501.3","description":"Determine level of NEPA review"},{"section":"40 CFR 1501.5","description":"Lead agency determination"},{"section":"40 CFR 1502","description":"EIS requirements and contents"},{"section":"40 CFR 1508.1","description":"Definitions — major federal action, significantly, human environment"}]', '["EIS","EA","FONSI","categorical_exclusion","record_of_decision","notice_of_intent","scoping_document","public_comment","supplemental_EIS","APA_challenge"]', '["california-regulatory-compliance-audit"]', 'Federal Agency (lead) / CEQ / Federal Courts (APA review)', 0, 1, datetime('now'), datetime('now'));

-- Clean Water Act
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_171', 'REGULIS', 'FEDERAL_STATUTE', 'US', '33 USC §§ 1251-1387 (Federal Water Pollution Control Act — Clean Water Act)', '33 USC §§ 1251-1387 / CWA', 'Clean Water Act — Regulation of Pollutant Discharges to Waters of the United States', 'Establishes structure for regulating discharge of pollutants into waters of the United States. NPDES permits required for point source discharges (§ 402). Section 404 permits for dredge/fill material in wetlands (Army Corps). Water quality standards set by states with EPA oversight. Technology-based effluent limitations. Total Maximum Daily Loads (TMDLs) for impaired waters. Citizen suit provision (§ 505). In California, State Water Resources Control Board and Regional Water Quality Control Boards administer.', '["Goal: restore and maintain chemical, physical, and biological integrity of waters","Prohibits discharge of pollutants from point sources without NPDES permit (§ 301/402)","NPDES permit program — delegated to states (CA: SWRCB/RWQCBs)","Technology-based effluent limitations for industrial dischargers","Water quality-based effluent limitations where technology-based insufficient","Section 404 — permit for discharge of dredge/fill material (Army Corps)","Section 401 — state water quality certification required for federal permits","TMDLs for impaired water bodies (§ 303(d))","Citizen suit provision: any citizen may enforce against violators (§ 505)","60-day notice requirement before citizen suit","Civil penalties: up to $64,618 per day per violation (2024 adjusted)","Criminal penalties for knowing violations"]', '[{"section":"1251","description":"Congressional declaration of goals and policy"},{"section":"1311","description":"Effluent limitations — prohibited discharges"},{"section":"1342","description":"NPDES permit program — point source discharges"},{"section":"1344","description":"Section 404 — dredge and fill permits (wetlands)"},{"section":"1341","description":"Section 401 — state water quality certification"},{"section":"1313(d)","description":"TMDLs — impaired waters list and load allocations"},{"section":"1362","description":"Definitions — point source, pollutant, navigable waters"},{"section":"1365","description":"Citizen suit provision — 60-day notice requirement"},{"section":"1319","description":"Enforcement — civil and criminal penalties"}]', '["NPDES_permit","section_404_permit","section_401_certification","discharge_monitoring_report","TMDL","stormwater_permit","NOV","citizen_suit_notice","water_quality_report","SWPPP"]', '["california-regulatory-compliance-audit"]', 'EPA / State Water Boards (CA: SWRCB, RWQCBs) / Army Corps (§ 404)', 1, 1, datetime('now'), datetime('now'));

-- Clean Air Act
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_172', 'REGULIS', 'FEDERAL_STATUTE', 'US', '42 USC §§ 7401-7671q (Clean Air Act)', '42 USC §§ 7401-7671q / CAA', 'Clean Air Act — National Ambient Air Quality Standards and Emission Controls', 'Comprehensive federal law regulating air emissions from stationary and mobile sources. EPA sets National Ambient Air Quality Standards (NAAQS) for six criteria pollutants. States must develop State Implementation Plans (SIPs) to achieve NAAQS. New Source Review (NSR) and Prevention of Significant Deterioration (PSD) for new/modified sources. Title V operating permits for major sources. Title VI: stratospheric ozone protection. In California, CARB and local Air Quality Management Districts (AQMDs) administer.', '["EPA sets NAAQS for six criteria pollutants: PM, ozone, SO2, NO2, CO, lead","States develop SIPs to achieve and maintain NAAQS","Nonattainment areas: stricter requirements for areas failing NAAQS","New Source Review (NSR): preconstruction permit for new/modified sources in nonattainment","Prevention of Significant Deterioration (PSD): permit for new sources in attainment areas","Title V: operating permits for major stationary sources","Hazardous Air Pollutants (HAPs): NESHAPs and MACT standards (§ 112)","Mobile source standards: vehicle emission standards (Title II)","California waiver: CARB may set stricter mobile source standards (§ 7543)","Citizen suit provision (§ 7604): 60-day notice required","Civil penalties: up to $109,024 per day per violation (2024 adjusted)"]', '[{"section":"7408-7409","description":"NAAQS — criteria pollutants and standards"},{"section":"7410","description":"State Implementation Plans (SIPs)"},{"section":"7470-7492","description":"Prevention of Significant Deterioration (PSD)"},{"section":"7501-7515","description":"Nonattainment areas — stricter requirements"},{"section":"7412","description":"Hazardous Air Pollutants — NESHAPs, MACT"},{"section":"7475","description":"New Source Review — preconstruction permit"},{"section":"7521","description":"Mobile source emission standards"},{"section":"7543","description":"California waiver for mobile sources"},{"section":"7604","description":"Citizen suit provision — 60-day notice"},{"section":"7661-7661f","description":"Title V operating permits"}]', '["NAAQS_determination","SIP","Title_V_permit","NSR_permit","PSD_permit","emission_inventory","air_quality_monitoring","CARB_waiver","citizen_suit_notice","NOV","MACT_standard"]', '["california-regulatory-compliance-audit"]', 'EPA / CARB / Local AQMDs (CA: SCAQMD, BAAQMD, etc.)', 1, 1, datetime('now'), datetime('now'));


